//! graphics tablet device
//!
//! The zwp_tablet_v2 interface represents one graphics tablet device. The
//! tablet interface itself does not generate events; all events are
//! generated by zwp_tablet_tool_v2 objects when in proximity above a tablet.
//!
//! A tablet has a number of static characteristics, e.g. device name and
//! pid/vid. These capabilities are sent in an event sequence after the
//! zwp_tablet_seat_v2.tablet_added event. This initial event sequence is
//! terminated by a zwp_tablet_v2.done event.

use crate::generated_helper::prelude::*;
use super::super::all_types::*;

/// A zwp_tablet_v2 proxy.
///
/// See the documentation of [the module][self] for the interface description.
pub struct MetaZwpTabletV2 {
    core: ProxyCore,
    handler: MessageHandlerHolder<dyn MetaZwpTabletV2MessageHandler>,
}

struct DefaultMessageHandler;

impl MetaZwpTabletV2MessageHandler for DefaultMessageHandler { }

impl MetaZwpTabletV2 {
    pub const XML_VERSION: u32 = 2;
}

impl MetaZwpTabletV2 {
    pub(crate) fn new(state: &Rc<InnerState>, version: u32) -> Rc<Self> {
        Rc::new(Self {
            core: ProxyCore::new(state, ProxyInterface::ZwpTabletV2, version),
            handler: Default::default(),
        })
    }
}

