/// bus type 
///
/// Describes the bus types this tablet is connected to.
#[derive(Copy, Clone, Eq, PartialEq, Ord, PartialOrd, Hash)]
#[allow(dead_code)]
pub struct MetaZwpTabletV2Bustype(pub u32);

impl MetaZwpTabletV2Bustype {
    /// USB
    #[allow(dead_code)]
    pub const USB: Self = Self(3);

    /// Bluetooth
    #[allow(dead_code)]
    pub const BLUETOOTH: Self = Self(5);

    /// Virtual
    #[allow(dead_code)]
    pub const VIRTUAL: Self = Self(6);

    /// Serial
    #[allow(dead_code)]
    pub const SERIAL: Self = Self(17);

    /// I2C
    #[allow(dead_code)]
    pub const I2C: Self = Self(24);
}

impl Debug for MetaZwpTabletV2Bustype {
    fn fmt(&self, f: &mut Formatter<'_>) -> std::fmt::Result {
        let name = match *self {
            Self::USB => "USB",
            Self::BLUETOOTH => "BLUETOOTH",
            Self::VIRTUAL => "VIRTUAL",
            Self::SERIAL => "SERIAL",
            Self::I2C => "I2C",
            _ => return Debug::fmt(&self.0, f),
        };
        f.write_str(name)
    }
}
